/*
 * Set up for future secure state handling, i.e. auth status, logged in user state
 * Code generated by ChatGPT 4.0 (OpenAI), 2024. Prompt: "Help me prepare for secure state handling in a React app"
 */

import { createContext, useContext, useState } from "react";
import { apiFetch } from "../services/api";

const AuthContext = createContext();

function getLocalJSON(key, fallback) {
	try {
		const value = localStorage.getItem(key);
		return value ? JSON.parse(value) : fallback;
	} catch {
		return fallback;
	}
}

export function AuthProvider({ children }) {
	const [user, setUser] = useState(() => getLocalJSON("user", null));
	const [token, setToken] = useState(
		() => localStorage.getItem("token") || null,
	);
	const [isAuthenticated, setIsAuthenticated] = useState(
		() => !!localStorage.getItem("token"),
	);

	const register = async (email, password) => {
		try {
			await apiFetch("/api/auth/register", {
				method: "POST",
				body: JSON.stringify({ email, password }),
			});
			return true;
		} catch (err) {
			console.error("register failed", err);
			return false;
		}
	};

	const login = async (email, password) => {
		// dev fallback for local testing
		if (email === "test@example.com" && password === "password") {
			const devToken = "dev-token";
			const nextUser = { email };
			setUser(nextUser);
			setToken(devToken);
			setIsAuthenticated(true);
			localStorage.setItem("user", JSON.stringify(nextUser));
			localStorage.setItem("token", devToken);
			return true;
		}

		try {
			const res = await apiFetch("/api/auth/login", {
				method: "POST",
				body: JSON.stringify({ email, password }),
			});

			if (res?.token) {
				const nextUser = { email };
				setUser(nextUser);
				setToken(res.token);
				setIsAuthenticated(true);
				localStorage.setItem("user", JSON.stringify(nextUser));
				localStorage.setItem("token", res.token);
				return true;
			}
		} catch (err) {
			console.error("login failed", err);
		}

		return false;
	};

	const logout = () => {
		setUser(null);
		setToken(null);
		setIsAuthenticated(false);
		localStorage.removeItem("user");
		localStorage.removeItem("token");
	};

	return (
		<AuthContext.Provider
			value={{ user, token, isAuthenticated, login, logout, register }}
		>
			{children}
		</AuthContext.Provider>
	);
}

export function useAuth() {
	return useContext(AuthContext);
}
